SELECT p.*, c.name as category_name, u.nickname as user_name FROM product p LEFT JOIN product_category c ON p.category_id = c.id LEFT JOIN sys_user u ON p.user_id = u.id
AND p.category_id = #{categoryId}
AND (p.name LIKE CONCAT('%', #{keyword}, '%') OR p.description LIKE CONCAT('%', #{keyword}, '%'))
AND p.status = #{status}
AND p.price >= #{minPrice}
AND p.price <= #{maxPrice}
ORDER BY p.sales DESC
ORDER BY p.price ASC
ORDER BY p.price DESC
ORDER BY p.create_time DESC
ORDER BY p.sales DESC, p.create_time DESC

